# --- tests/test_native_tool_search_vcr.py ---

async def test_anthropic_native_tool_search(allow_model_requests: None) -> None:
    """Test Anthropic Beta API with tool_search_tool_bm25.

    Sends tools with a tool_search_tool_bm25 entry and deferred tools.
    The model should discover and call get_exchange_rate via native search.
    """
    client = anthropic.AsyncAnthropic()

    custom_tools: list[BetaToolParam] = [
        BetaToolParam(
            name=str(_TOOLS[0]['name']),
            description=str(_TOOLS[0].get('description', '')),
            input_schema=_TOOLS[0]['parameters'],  # pyright: ignore[reportArgumentType]
        ),
        *(
            BetaToolParam(
                name=str(tool_def['name']),
                description=str(tool_def.get('description', '')),
                input_schema=tool_def['parameters'],  # pyright: ignore[reportArgumentType]
                defer_loading=True,
            )
            for tool_def in _TOOLS[1:]
        ),
    ]
    tools: list[BetaToolUnionParam] = [
        *custom_tools,
        BetaToolSearchToolBm25_20251119Param(
            type='tool_search_tool_bm25_20251119',
            name='tool_search_tool_bm25',
        ),
    ]

    response = await client.beta.messages.create(
        model='claude-sonnet-4-5',
        max_tokens=1024,
        tools=tools,
        messages=[{'role': 'user', 'content': 'What is the current exchange rate from USD to EUR?'}],
    )

    tool_use_blocks = [block for block in response.content if block.type == 'tool_use']
    server_tool_blocks = [block for block in response.content if block.type == 'server_tool_use']

    assert len(server_tool_blocks) >= 1
    assert any(block.name == 'get_exchange_rate' for block in tool_use_blocks)


# --- tests/test_streaming_errors.py ---

async def test_bedrock_stream_creation_error(allow_model_requests: None):
    """ClientError during stream creation is wrapped as ModelHTTPError."""
    error = ClientError(
        {
            'Error': {'Code': 'ThrottlingException', 'Message': 'Rate exceeded'},
            'ResponseMetadata': {
                'RequestId': '',
                'HostId': '',
                'HTTPStatusCode': 429,
                'HTTPHeaders': {},
                'RetryAttempts': 0,
            },
        },
        'converse_stream',
    )
    model = _bedrock_model_with_error(error)
    agent = Agent(model)

    with pytest.raises(ModelHTTPError) as exc_info:
        async with agent.run_stream('hello'):
            pass

    assert exc_info.value.status_code == 429
    assert exc_info.value.model_name == 'us.amazon.nova-micro-v1:0'

async def test_bedrock_stream_non_http_error(allow_model_requests: None):
    """ClientError without HTTP status code is wrapped as ModelAPIError."""
    error = ClientError(
        {'Error': {'Code': 'TestException', 'Message': 'broken connection'}},
        'converse_stream',
    )
    model = _bedrock_model_with_error(error)
    agent = Agent(model)

    with pytest.raises(ModelAPIError) as exc_info:
        async with agent.run_stream('hello'):
            pass

    assert 'broken connection' in exc_info.value.message

async def test_bedrock_midstream_error(
    allow_model_requests: None, error_factory: Any, expected_exc: type[Exception], check_status: int | None
):
    """ClientError during stream iteration is wrapped correctly."""
    model = _bedrock_model_with_midstream_error(error_factory())
    agent = Agent(model)

    with pytest.raises(expected_exc) as exc_info:
        async with agent.run_stream('hello') as result:
            async for _ in result.stream_text():
                pass

    if check_status is not None:
        assert isinstance(exc_info.value, ModelHTTPError)
        assert exc_info.value.status_code == check_status


# --- tests/test_thinking.py ---

    async def test_thinking_setting_produces_output(self):
        """Basic smoke test: agent with thinking=True runs successfully."""
        model = _make_model(supports_thinking=True)
        agent = Agent(model, model_settings=ModelSettings(thinking=True))
        result = await agent.run('test')
        assert result.output == 'ok'

    async def test_capability_flows_through_to_model(self):
        """Thinking capability's model settings flow through to resolved params."""
        captured_params: list[ModelRequestParameters] = []

        def _capture(messages: list[ModelMessage], info: AgentInfo) -> ModelResponse:
            captured_params.append(info.model_request_parameters)
            return ModelResponse(parts=[TextPart(content='done')])

        model = FunctionModel(
            _capture,
            profile=ModelProfile(supports_thinking=True),
        )
        agent = Agent(model, capabilities=[Thinking(effort='high')])
        result = await agent.run('test')
        assert result.output == 'done'
        assert len(captured_params) == 1
        assert captured_params[0].thinking == 'high'

    async def test_capability_default_effort_flows_through(self):
        """Thinking() with default effort=True flows through."""
        captured_params: list[ModelRequestParameters] = []

        def _capture(messages: list[ModelMessage], info: AgentInfo) -> ModelResponse:
            captured_params.append(info.model_request_parameters)
            return ModelResponse(parts=[TextPart(content='done')])

        model = FunctionModel(
            _capture,
            profile=ModelProfile(supports_thinking=True),
        )
        agent = Agent(model, capabilities=[Thinking()])
        result = await agent.run('test')
        assert result.output == 'done'
        assert captured_params[0].thinking is True

    async def test_capability_silently_ignored_on_unsupported_model(self):
        """Thinking capability on unsupported model -> params.thinking stays None."""
        captured_params: list[ModelRequestParameters] = []

        def _capture(messages: list[ModelMessage], info: AgentInfo) -> ModelResponse:
            captured_params.append(info.model_request_parameters)
            return ModelResponse(parts=[TextPart(content='done')])

        model = FunctionModel(
            _capture,
            profile=ModelProfile(supports_thinking=False),
        )
        agent = Agent(model, capabilities=[Thinking(effort='high')])
        result = await agent.run('test')
        assert result.output == 'done'
        assert captured_params[0].thinking is None

    async def test_model_settings_override_with_thinking(self):
        """run-level model_settings with thinking override agent-level capability."""
        captured_params: list[ModelRequestParameters] = []
        captured_settings: list[ModelSettings | None] = []

        def _capture(messages: list[ModelMessage], info: AgentInfo) -> ModelResponse:
            captured_params.append(info.model_request_parameters)
            captured_settings.append(info.model_settings)
            return ModelResponse(parts=[TextPart(content='done')])

        model = FunctionModel(
            _capture,
            profile=ModelProfile(supports_thinking=True),
        )
        agent = Agent(model, capabilities=[Thinking(effort='low')])
        result = await agent.run('test', model_settings=ModelSettings(thinking='high'))
        assert result.output == 'done'
        # Run-level settings override capability settings via merge_model_settings
        assert captured_params[0].thinking == 'high'

    async def test_thinking_false_capability_on_always_enabled(self):
        """Thinking(effort=False) on always-on model -> silently ignored."""
        captured_params: list[ModelRequestParameters] = []

        def _capture(messages: list[ModelMessage], info: AgentInfo) -> ModelResponse:
            captured_params.append(info.model_request_parameters)
            return ModelResponse(parts=[TextPart(content='done')])

        model = FunctionModel(
            _capture,
            profile=ModelProfile(thinking_always_enabled=True),
        )
        agent = Agent(model, capabilities=[Thinking(effort=False)])
        result = await agent.run('test')
        assert result.output == 'done'
        assert captured_params[0].thinking is None


